import requests
import json
import sys
from requests.auth import HTTPBasicAuth
from typing import List, Dict, Any

class RabbitMQConfig:
    def __init__(self, host: str, port: int = 15672, username: str = "admin", password: str = "admin"):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.base_url = f"http://{self.host}:{self.port}/api"
        self.auth = HTTPBasicAuth(self.username, self.password)
        self.session = requests.Session()
        self.session.auth = self.auth
        
    def _make_request(self, method: str, endpoint: str, data: Dict = None) -> requests.Response:
        url = f"{self.base_url}/{endpoint}"
        headers = {'Content-Type': 'application/json'}
        
        try:
            if method.upper() == "GET":
                response = self.session.get(url, headers=headers)
            elif method.upper() == "POST":
                response = self.session.post(url, headers=headers, data=json.dumps(data))
            elif method.upper() == "PUT":
                response = self.session.put(url, headers=headers, data=json.dumps(data))
            elif method.upper() == "DELETE":
                response = self.session.delete(url, headers=headers)
            
            response.raise_for_status()
            return response
            
        except requests.exceptions.RequestException as e:
            print(f"Error making request to {url}: {e}")
            raise
    
    def create_vhost(self, vhost_name: str) -> bool:
        try:
            self._make_request("PUT", f"vhosts/{vhost_name}")
            print(f"Created vhost: {vhost_name}")
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 409:
                print(f"Vhost {vhost_name} already exists")
                return True
            else:
                print(f"Failed to create vhost {vhost_name}: {e}")
                return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        try:
            self._make_request("DELETE", f"vhosts/{vhost_name}")
            print(f"Deleted vhost: {vhost_name}")
            return True
        except requests.exceptions.HTTPError as e:
            print(f"Failed to delete vhost {vhost_name}: {e}")
            return False
    
    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        try:
            user_data = {
                "password": password,
                "tags": tags
            }
            self._make_request("PUT", f"users/{username}", data=user_data)
            print(f"Created user: {username}")
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 409:
                print(f"User {username} already exists")
                return True
            else:
                print(f"Failed to create user {username}: {e}")
                return False
    
    def delete_user(self, username: str) -> bool:
        try:
            self._make_request("DELETE", f"users/{username}")
            print(f"Deleted user: {username}")
            return True
        except requests.exceptions.HTTPError as e:
            print(f"Failed to delete user {username}: {e}")
            return False
    
    def set_permissions(self, username: str, vhost_name: str, configure: str, write: str, read: str) -> bool:
        try:
            permissions_data = {
                "configure": configure,
                "write": write,
                "read": read
            }
            self._make_request("PUT", f"permissions/{vhost_name}/{username}", data=permissions_data)
            print(f"Set permissions for user {username} on vhost {vhost_name}")
            return True
        except requests.exceptions.HTTPError as e:
            print(f"Failed to set permissions for user {username} on vhost {vhost_name}: {e}")
            return False
    
    def set_user_permissions(self, username: str, vhost_name: str, permissions: Dict[str, str]) -> bool:
        """Set permissions for a user on a specific vhost"""
        return self.set_permissions(username, vhost_name, 
                                  permissions.get('configure', ''), 
                                  permissions.get('write', ''), 
                                  permissions.get('read', ''))
    
    def setup_tenant_environment(self, tenant_name: str, user_password: str, 
                               permissions: Dict[str, str] = None) -> bool:
        """Setup complete tenant environment"""
        if not permissions:
            permissions = {
                "configure": ".*",
                "write": ".*",
                "read": ".*"
            }
        
        vhost_name = f"/{tenant_name}"
        
        # Create vhost
        if not self.create_vhost(vhost_name):
            return False
        
        # Create user
        username = f"{tenant_name}_user"
        if not self.create_user(username, user_password):
            return False
        
        # Set permissions
        if not self.set_user_permissions(username, vhost_name, permissions):
            return False
        
        return True
    
    def get_vhosts(self) -> List[Dict[str, Any]]:
        """Get list of all vhosts"""
        try:
            response = self._make_request("GET", "vhosts")
            return response.json()
        except requests.exceptions.RequestException as e:
            print(f"Failed to get vhosts: {e}")
            return []
    
    def get_users(self) -> List[Dict[str, Any]]:
        """Get list of all users"""
        try:
            response = self._make_request("GET", "users")
            return response.json()
        except requests.exceptions.RequestException as e:
            print(f"Failed to get users: {e}")
            return []

def main():
    # Configuration
    RMQ_HOST = "localhost"
